"use client";
import * as React from "react";
import { motion, AnimatePresence } from "framer-motion";

export interface AnimatedListProps {
  items: React.ReactNode[];
  delay?: number;
  className?: string;
}

export function AnimatedList({ items, delay = 1500, className }: AnimatedListProps) {
  const [index, setIndex] = React.useState(0);

  React.useEffect(() => {
    if (items.length === 0) return;
    const id = setInterval(() => {
      setIndex((i) => (i + 1) % items.length);
    }, delay);
    return () => clearInterval(id);
  }, [items.length, delay]);

  if (items.length === 0) return null;

  return (
    <div className={className}>
      <AnimatePresence mode="popLayout">
        <motion.div
          key={index}
          initial={{ opacity: 0, y: -10 }}
          animate={{ opacity: 1, y: 0 }}
          exit={{ opacity: 0, y: 10 }}
          transition={{ duration: 0.3 }}
        >
          {items[index]}
        </motion.div>
      </AnimatePresence>
    </div>
  );
}

"use client";
import * as React from "react";
import { cn } from "@/lib/utils";

export interface ShinyGradientButtonProps
  extends React.ButtonHTMLAttributes<HTMLButtonElement> {}

export const ShinyGradientButton = React.forwardRef<
  HTMLButtonElement,
  ShinyGradientButtonProps
>(({ className, children, ...props }, ref) => {
  return (
    <button
      ref={ref}
      className={cn(
        "relative inline-flex h-12 items-center justify-center overflow-hidden rounded-md px-6 font-medium text-white",
        "bg-[linear-gradient(110deg,#1f2937,45%,#4b5563,55%,#1f2937)] bg-[length:200%_100%]",
        "animate-shiny-gradient transition-colors focus:outline-none focus:ring-2 focus:ring-slate-400 focus:ring-offset-2 focus:ring-offset-slate-50",
        className,
      )}
      {...props}
    >
      {children}
    </button>
  );
});
ShinyGradientButton.displayName = "ShinyGradientButton";

"use client";
import * as React from "react";
import { cn } from "@/lib/utils";

export interface GlowCardProps extends React.HTMLAttributes<HTMLDivElement> {
  glowColor?: string;
}

export const GlowCard = React.forwardRef<HTMLDivElement, GlowCardProps>(
  ({ className, children, glowColor = "rgba(99,102,241,0.5)", style, ...props }, ref) => {
    const mergedStyle: React.CSSProperties = {
      boxShadow: `0 0 40px -12px ${glowColor}`,
      ...style,
    };
    return (
      <div
        ref={ref}
        style={mergedStyle}
        className={cn(
          "relative rounded-xl border border-white/10 bg-zinc-900/60 p-6 backdrop-blur transition-shadow",
          className,
        )}
        {...props}
      >
        {children}
      </div>
    );
  },
);
GlowCard.displayName = "GlowCard";
